TriggerOraclev10g.body:
DECLARE envbq_status number; valor_envbq_update number; vro_error tkr_errores%ROWTYPE; BEGIN -- En el caso de INSERT IF INSERTING THEN
SELECT (SELECT ENVIO_BQ FROM TKRBQ_CIE WHERE ID = :NEW.ID AND ENVIO_BQ != 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NOT NULL THEN DELETE TKRBQ_CIE WHERE ID = :NEW.ID AND ENVIO_BQ != 1; END IF;
INSERT INTO TKRBQ_CIE ( ENVIO_BQ, ID, CODIGO_CIE, DESCRIPCION_CIE, ID_CAPITULO, FECHA_CREACION, ID_PATOLOGIA ) VALUES ( 0, -- ENVIO_BQ por defecto :NEW.ID, :NEW.CODIGO_CIE, :NEW.DESCRIPCION_CIE, :NEW.ID_CAPITULO, :NEW.FECHA_CREACION, :NEW.ID_PATOLOGIA ); END IF;
-- En el caso de UPDATE IF UPDATING THEN SELECT (SELECT ENVIO_BQ FROM TKRBQ_CIE WHERE ID = :NEW.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NULL THEN
INSERT INTO TKRBQ_CIE ( ENVIO_BQ, ID, CODIGO_CIE, DESCRIPCION_CIE, ID_CAPITULO, FECHA_CREACION, ID_PATOLOGIA ) VALUES ( 2, -- ENVIO_BQ por defecto :NEW.ID, :NEW.CODIGO_CIE, :NEW.DESCRIPCION_CIE, :NEW.ID_CAPITULO, :NEW.FECHA_CREACION, :NEW.ID_PATOLOGIA );
ELSE IF envbq_status = 0 THEN valor_envbq_update := 0; ELSE valor_envbq_update := 2; END IF;
UPDATE TKRBQ_CIE SET ENVIO_BQ = valor_envbq_update, ID = :NEW.ID, CODIGO_CIE = :NEW.CODIGO_CIE, DESCRIPCION_CIE = :NEW.DESCRIPCION_CIE, ID_CAPITULO = :NEW.ID_CAPITULO, FECHA_CREACION = :NEW.FECHA_CREACION, ID_PATOLOGIA = :NEW.ID_PATOLOGIA WHERE ID = :OLD.ID AND ENVIO_BQ != 1; END IF; END IF;
-- Caso DELETE IF DELETING THEN
SELECT (SELECT ENVIO_BQ FROM TKRBQ_CIE WHERE ID = :OLD.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NOT NULL THEN DELETE TKRBQ_CIE WHERE ID = :OLD.ID AND ENVIO_BQ != 1; END IF;
INSERT INTO TKRBQ_CIE ( ENVIO_BQ, ID, CODIGO_CIE, DESCRIPCION_CIE, ID_CAPITULO, FECHA_CREACION, ID_PATOLOGIA ) VALUES ( -1, -- ENVIO_BQ para DELETE :OLD.ID, :OLD.CODIGO_CIE, :OLD.DESCRIPCION_CIE, :OLD.ID_CAPITULO, :OLD.FECHA_CREACION, :OLD.ID_PATOLOGIA ); END IF;
EXCEPTION WHEN OTHERS THEN vro_error.nombre_programa := 'TRG_SYNC_TKR_CIE'; vro_error.nombre_metodo := 'TRIGGER_SYNC_BQ'; vro_error.parametros := 'id de consultas: '||:old.id; uti_ge_excepciones_pkg.p_grabar_log (vro_error);
END;
